import{_ as e,o as a,c as o,aj as d}from"./chunks/framework.BASLC-SQ.js";const m=JSON.parse('{"title":"Getting Started","description":"","frontmatter":{},"headers":[],"relativePath":"doc/getting-started.md","filePath":"doc/getting-started.md","lastUpdated":1783819531000}'),s={name:"doc/getting-started.md"};function r(i,t,n,h,l,c){return a(),o("div",null,[...t[0]||(t[0]=[d('<h1 id="getting-started" tabindex="-1">Getting Started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting Started&quot;">​</a></h1><p>First, you need to pick a shadowsocks server and client implementation. Any implementation below is compatible with each other.</p><h2 id="cli-implementations" tabindex="-1">CLI implementations <a class="header-anchor" href="#cli-implementations" aria-label="Permalink to &quot;CLI implementations&quot;">​</a></h2><ul><li><a href="https://github.com/shadowsocks/shadowsocks-libev" target="_blank" rel="noreferrer">shadowsocks-libev</a>: Lightweight C implementation for embedded devices and low end boxes. Very small footprint (several megabytes) for thousands of connections.</li><li><a href="https://github.com/shadowsocks/go-shadowsocks2" target="_blank" rel="noreferrer">go-shadowsocks2</a>: Go implementation focusing on core features and code reusability.</li><li><a href="https://github.com/shadowsocks/shadowsocks-rust" target="_blank" rel="noreferrer">shadowsocks-rust</a>: A rust port of shadowsocks.</li></ul><h3 id="feature-comparison" tabindex="-1">Feature comparison <a class="header-anchor" href="#feature-comparison" aria-label="Permalink to &quot;Feature comparison&quot;">​</a></h3><table><thead><tr><th></th><th><a href="https://github.com/shadowsocks/shadowsocks-libev">ss-libev</a></th><th><a href="https://github.com/shadowsocks/go-shadowsocks2">go-ss2</a></th><th><a href="https://github.com/shadowsocks/shadowsocks-rust">ss-rust</a></th></tr></thead><tbody><tr><td><a href="https://en.wikipedia.org/wiki/TCP_Fast_Open">TCP Fast Open</a></td><td>✓</td><td>✗</td><td>✓</td></tr><tr><td>Multiuser</td><td>✓</td><td>✗</td><td>✓</td></tr><tr><td>Management API</td><td>✓</td><td>✗</td><td>✓</td></tr><tr><td>Redirect mode</td><td>✓</td><td>✓</td><td>✓</td></tr><tr><td>Tunnel mode</td><td>✓</td><td>✓</td><td>✓</td></tr><tr><td>UDP Relay</td><td>✓</td><td>✓</td><td>✓</td></tr><tr><td><a href="https://en.wikipedia.org/wiki/Multipath_TCP">MPTCP</a></td><td>✓</td><td>✗</td><td>✓</td></tr><tr><td><a href="aead">AEAD ciphers</a></td><td>✓</td><td>✓</td><td>✓</td></tr><tr><td><a href="sip003">Plugin</a></td><td>✓</td><td>✗</td><td>✓</td></tr><tr><td><a href="https://github.com/shadowsocks/shadowsocks-org/issues/180">Plugin UDP (Experimental)</a></td><td>✗</td><td>✗</td><td>✓</td></tr></tbody></table><h2 id="gui-clients" tabindex="-1">GUI Clients <a class="header-anchor" href="#gui-clients" aria-label="Permalink to &quot;GUI Clients&quot;">​</a></h2><ul><li><a href="https://madeye.github.io/meow-ios/" target="_blank" rel="noreferrer">meow</a>: iOS client.</li><li><a href="https://github.com/shadowsocks/shadowsocks-android" target="_blank" rel="noreferrer">shadowsocks-android</a>: Android client.</li><li><a href="https://github.com/shadowsocks/shadowsocks-csharp" target="_blank" rel="noreferrer">shadowsocks-windows</a>: Windows client.</li><li><a href="https://github.com/shadowsocks/ShadowsocksX-NG" target="_blank" rel="noreferrer">shadowsocksX-NG</a>: MacOS client.</li><li><a href="https://github.com/shadowsocks/shadowsocks-qt5" target="_blank" rel="noreferrer">shadowsocks-qt5</a>: Cross-platform client for Windows/MacOS/Linux.</li></ul><h3 id="recommended-ios-client-meow" tabindex="-1">Recommended iOS client: meow <a class="header-anchor" href="#recommended-ios-client-meow" aria-label="Permalink to &quot;Recommended iOS client: meow&quot;">​</a></h3><p><a href="https://madeye.github.io/meow-ios/" target="_blank" rel="noreferrer">meow</a> is the recommended Shadowsocks client for iOS. Its core Shadowsocks-related features are:</p><ul><li>Shadowsocks outbound protocol support, powered by the meow-rs engine (Trojan and VLESS outbounds are also available).</li><li>AEAD ciphers (aes-128-gcm, aes-192-gcm, aes-256-gcm, chacha20-ietf-poly1305, xchacha20-ietf-poly1305) and <a href="./sip022.html">SIP022</a> AEAD-2022 ciphers (2022-blake3-aes-128-gcm, 2022-blake3-aes-256-gcm, 2022-blake3-chacha20-poly1305).</li><li><a href="./sip002.html">SIP002</a> <code>ss://</code> share links via manual paste or QR code scan, including the plain <code>method:password</code> userinfo form used by AEAD-2022, and the legacy base64 form. Servers and subscription URLs can also be exported as QR codes for sharing.</li><li><a href="./sip003.html">SIP003</a> plugins, implemented natively in-process (iOS does not allow plugin subprocesses): simple-obfs (<code>obfs-local</code>, http and tls modes) and v2ray-plugin (WebSocket with optional TLS).</li><li>System-wide VPN via a NetworkExtension packet tunnel — no per-app configuration required.</li><li>UDP relay (QUIC/HTTP3 reliability depends on the outbound proxy and may fall back to TCP).</li><li>Rule-based routing with domain, IP, GeoIP, and GeoSITE rules, plus CN-IP TCP bypass for split routing.</li><li>DNS over HTTPS.</li><li>Clash-style YAML subscriptions with profile switching, per-app proxy group selection, and latency testing.</li><li>Live traffic throughput monitoring and per-day usage charts.</li><li>Runs fully on-device with no data collection. Requires iOS 17+; distributed via TestFlight.</li></ul><h3 id="feature-comparison-1" tabindex="-1">Feature comparison <a class="header-anchor" href="#feature-comparison-1" aria-label="Permalink to &quot;Feature comparison&quot;">​</a></h3><p>For meow&#39;s full iOS feature set, see the section above.</p><table><thead><tr><th></th><th><a href="https://github.com/shadowsocks/shadowsocks-csharp">ss-win</a></th><th><a href="https://github.com/shadowsocks/ShadowsocksX-NG">ssx-ng</a></th><th><a href="https://github.com/shadowsocks/shadowsocks-qt5">ss-qt5</a></th><th><a href="https://github.com/shadowsocks/shadowsocks-android">ss-android</a></th><th><a href="https://madeye.github.io/meow-ios/">meow</a></th></tr></thead><tbody><tr><td>System Proxy</td><td>✓</td><td>✓</td><td>✗</td><td>✓</td><td>✓</td></tr><tr><td>CHNRoutes</td><td>✓</td><td>✓</td><td>✗</td><td>✓</td><td>✓</td></tr><tr><td>PAC Configuration</td><td>✓</td><td>✓</td><td>✗</td><td>✗</td><td>✗</td></tr><tr><td>Profile Switching</td><td>✓</td><td>✓</td><td>✓</td><td>✓</td><td>✓</td></tr><tr><td>QR Code Scan</td><td>✓</td><td>✓</td><td>✓</td><td>✓</td><td>✓</td></tr><tr><td>QR Code Generation</td><td>✓</td><td>✓</td><td>✓</td><td>✓</td><td>✓</td></tr></tbody></table>',14)])])}const u=e(s,[["render",r]]);export{m as __pageData,u as default};
